    call gc_register_root
    lea rcx, [rel masm_prefix]
    call gc_register_root
    lea rcx, [rel masm_suffix]
    call gc_register_root
    lea rcx, [rel fmt_dec]
    call gc_register_root
    lea rcx, [rel msg_usage]
    call gc_register_root
    lea rcx, [rel msg_read_err]
    call gc_register_root
    lea rcx, [rel msg_lex_err]
    call gc_register_root
    lea rcx, [rel msg_parse_err]
    call gc_register_root
    lea rcx, [rel msg_mem_err]
    call gc_register_root
    lea rcx, [rel msg_write_err]
    call gc_register_root
    lea rcx, [rel msg_syntax]
    call gc_register_root
    ; Call user main function
    sub rsp, 48      ; Shadow + space for argc/argv
    lea rcx, [rsp + 32]  ; &argc
    lea rdx, [rsp + 40]  ; &argv
    extern masm_entry_get_args
    call masm_entry_get_args
    mov ecx, [rsp + 32]  ; argc
    mov rdx, [rsp + 40]  ; argv
    call main
    add rsp, 48      ; Restore stack
    mov [rsp + 32], rax ; Preserve main return code
    extern gc_shutdown
    call gc_shutdown
    mov rcx, [rsp + 32] ; Use main return as exit code
    extern ExitProcess
    call ExitProcess

